bool sb_queue_Isolette_Environment_Heat_1_dequeue(
  sb_queue_Isolette_Environment_Heat_1_Recv_t *recvQueue,
  sb_event_counter_t *numDropped,
  Isolette_Environment_Heat *data) {

  sb_event_counter_t *numRecv = &recvQueue->numRecv;
  sb_queue_Isolette_Environment_Heat_1_t *queue = recvQueue->queue;

  // Get a copy of numSent so we can see if it changes during read
