  // incremented. Thus there are really only (SB_QUEUE_ISOLETTE_ENVIRONMENT_HEAT_1_SIZE - 1)
  // elements in the queue.
  *numDropped = (numNew <= SB_QUEUE_ISOLETTE_ENVIRONMENT_HEAT_1_SIZE - 1) ? 0 : numNew - SB_QUEUE_ISOLETTE_ENVIRONMENT_HEAT_1_SIZE + 1;

